// src/main/java/com/example/userapp/network/AuthInterceptor.java
package com.example.userapp.network;

import java.io.IOException;

import okhttp3.Interceptor;
import okhttp3.Request;
import okhttp3.Response;

public class AuthInterceptor implements Interceptor {

    private final TokenProvider tokenProvider;

    public interface TokenProvider {
        String getToken();
    }

    public AuthInterceptor(TokenProvider tokenProvider) {
        this.tokenProvider = tokenProvider;
    }

    @Override
    public Response intercept(Chain chain) throws IOException {
        Request originalRequest = chain.request();

        String token = tokenProvider != null ? tokenProvider.getToken() : null;
        if (token == null || token.isEmpty()) {
            return chain.proceed(originalRequest);
        }

        Request authenticatedRequest = originalRequest.newBuilder()
                .header("Authorization", "Bearer " + token)
                .header("Accept", "application/json")
                .build();

        return chain.proceed(authenticatedRequest);
    }
}


// src/main/java/com/example/userapp/network/RetryInterceptor.java
package com.example.userapp.network;

import java.io.IOException;

import okhttp3.Interceptor;
import okhttp3.Request;
import okhttp3.Response;

public class RetryInterceptor implements Interceptor {

    private final int maxRetries;

    public RetryInterceptor(int maxRetries) {
        this.maxRetries = maxRetries;
    }

    @Override
    public Response intercept(Chain chain) throws IOException {
        Request request = chain.request();
        IOException lastException = null;

        for (int attempt = 0; attempt <= maxRetries; attempt++) {
            try {
                Response response = chain.proceed(request);
                if (response.isSuccessful() || attempt >= maxRetries) {
                    return response;
                }
                int code = response.code();
                response.close();
                if (code < 500) {
                    return chain.proceed(request);
                }
            } catch (IOException e) {
                lastException = e;
                if (attempt >= maxRetries) {
                    throw e;
                }
            }

            try {
                long backoff = (long) Math.pow(2, attempt) * 1000;
                Thread.sleep(backoff);
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
                throw new IOException("Retry interrupted", e);
            }
        }

        throw lastException != null ? lastException : new IOException("Request failed after retries");
    }
}


