package com.example.userapp.viewmodel;

import androidx.lifecycle.LiveData;
import androidx.lifecycle.MutableLiveData;
import androidx.lifecycle.ViewModel;

import com.example.userapp.model.User;
import com.example.userapp.repository.UserRepository;

import java.util.List;

public class UserViewModel extends ViewModel {

    private final UserRepository userRepository;

    private final MutableLiveData<Resource<List<User>>> usersLiveData = new MutableLiveData<>();
    private final MutableLiveData<Resource<User>> userDetailLiveData = new MutableLiveData<>();

    public UserViewModel() {
        this.userRepository = new UserRepository();
    }

    public UserViewModel(UserRepository userRepository) {
        this.userRepository = userRepository;
    }

    public LiveData<Resource<List<User>>> getUsersLiveData() {
        return usersLiveData;
    }

    public LiveData<Resource<User>> getUserDetailLiveData() {
        return userDetailLiveData;
    }

    public void loadUsers() {
        usersLiveData.setValue(Resource.loading());
        userRepository.fetchUsers(new UserRepository.RepositoryCallback<List<User>>() {
            @Override
            public void onSuccess(List<User> data) {
                usersLiveData.postValue(Resource.success(data));
            }

            @Override
            public void onError(String errorMessage) {
                usersLiveData.postValue(Resource.error(errorMessage));
            }
        });
    }

    public void loadUsers(int page, int perPage) {
        usersLiveData.setValue(Resource.loading());
        userRepository.fetchUsers(page, perPage, new UserRepository.RepositoryCallback<List<User>>() {
            @Override
            public void onSuccess(List<User> data) {
                usersLiveData.postValue(Resource.success(data));
            }

            @Override
            public void onError(String errorMessage) {
                usersLiveData.postValue(Resource.error(errorMessage));
            }
        });
    }

    public void loadUserDetail(int userId) {
        userDetailLiveData.setValue(Resource.loading());
        userRepository.fetchUser(userId, new UserRepository.RepositoryCallback<User>() {
            @Override
            public void onSuccess(User data) {
                userDetailLiveData.postValue(Resource.success(data));
            }

            @Override
            public void onError(String errorMessage) {
                userDetailLiveData.postValue(Resource.error(errorMessage));
            }
        });
    }
}


