package com.example.userapp.ui.adapter;

import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.TextView;

import androidx.annotation.NonNull;
import androidx.recyclerview.widget.RecyclerView;

import com.example.userapp.R;
import com.example.userapp.model.User;

import java.util.ArrayList;
import java.util.List;

public class UserAdapter extends RecyclerView.Adapter<UserAdapter.UserViewHolder> {

    private final List<User> users = new ArrayList<>();
    private OnUserClickListener listener;

    public interface OnUserClickListener {
        void onUserClick(User user);
    }

    public void setOnUserClickListener(OnUserClickListener listener) {
        this.listener = listener;
    }

    public void setUsers(List<User> newUsers) {
        users.clear();
        if (newUsers != null) {
            users.addAll(newUsers);
        }
        notifyDataSetChanged();
    }

    @NonNull
    @Override
    public UserViewHolder onCreateViewHolder(@NonNull ViewGroup parent, int viewType) {
        View view = LayoutInflater.from(parent.getContext())
                .inflate(R.layout.item_user, parent, false);
        return new UserViewHolder(view);
    }

    @Override
    public void onBindViewHolder(@NonNull UserViewHolder holder, int position) {
        User user = users.get(position);
        holder.bind(user);
        holder.itemView.setOnClickListener(v -> {
            if (listener != null) {
                listener.onUserClick(user);
            }
        });
    }

    @Override
    public int getItemCount() {
        return users.size();
    }

    static class UserViewHolder extends RecyclerView.ViewHolder {

        private final TextView nameTextView;
        private final TextView emailTextView;
        private final TextView phoneTextView;

        UserViewHolder(@NonNull View itemView) {
            super(itemView);
            nameTextView = itemView.findViewById(R.id.tv_user_name);
            emailTextView = itemView.findViewById(R.id.tv_user_email);
            phoneTextView = itemView.findViewById(R.id.tv_user_phone);
        }

        void bind(User user) {
            nameTextView.setText(user.getName());
            emailTextView.setText(user.getEmail());
            if (user.getPhone() != null && !user.getPhone().isEmpty()) {
                phoneTextView.setVisibility(View.VISIBLE);
                phoneTextView.setText(user.getPhone());
            } else {
                phoneTextView.setVisibility(View.GONE);
            }
        }
    }
}


// src/main/java/com/example/userapp/ui/MainActivity.java
package com.example.userapp.ui;

import android.os.Bundle;
import android.view.View;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;
import androidx.lifecycle.ViewModelProvider;
import androidx.recyclerview.widget.LinearLayoutManager;
import androidx.swiperefreshlayout.widget.SwipeRefreshLayout;

import com.example.userapp.BuildConfig;
import com.example.userapp.R;
import com.example.userapp.databinding.ActivityMainBinding;
import com.example.userapp.model.User;
import com.example.userapp.ui.adapter.UserAdapter;
import com.example.userapp.viewmodel.Resource;
import com.example.userapp.viewmodel.UserViewModel;

public class MainActivity extends AppCompatActivity {

    private ActivityMainBinding binding;
    private UserViewModel userViewModel;
    private UserAdapter userAdapter;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        binding = ActivityMainBinding.inflate(getLayoutInflater());
        setContentView(binding.getRoot());

        setupToolbar();
        setupRecyclerView();
        setupSwipeRefresh();
        setupViewModel();

        userViewModel.loadUsers();
    }

    private void setupToolbar() {
        setSupportActionBar(binding.toolbar);
        if (getSupportActionBar() != null) {
            String title = "Users";
            if (!"production".equals(BuildConfig.ENVIRONMENT)) {
                title += " [" + BuildConfig.ENVIRONMENT.toUpperCase() + "]";
            }
            getSupportActionBar().setTitle(title);
        }
    }

    private void setupRecyclerView() {
        userAdapter = new UserAdapter();
        userAdapter.setOnUserClickListener(this::onUserClicked);
        binding.recyclerViewUsers.setLayoutManager(new LinearLayoutManager(this));
        binding.recyclerViewUsers.setAdapter(userAdapter);
    }

    private void setupSwipeRefresh() {
        binding.swipeRefreshLayout.setOnRefreshListener(() -> userViewModel.loadUsers());
    }

    private void setupViewModel() {
        userViewModel = new ViewModelProvider(this).get(UserViewModel.class);
        userViewModel.getUsersLiveData().observe(this, resource -> {
            switch (resource.getStatus()) {
                case LOADING:
                    showLoading();
                    break;
                case SUCCESS:
                    showUsers(resource);
                    break;
                case ERROR:
                    showError(resource.getMessage());
                    break;
            }
        });
    }

    private void showLoading() {
        if (!binding.swipeRefreshLayout.isRefreshing()) {
            binding.progressBar.setVisibility(View.VISIBLE);
        }
        binding.tvError.setVisibility(View.GONE);
        binding.tvEmptyState.setVisibility(View.GONE);
    }

    private void showUsers(Resource resource) {
        binding.progressBar.setVisibility(View.GONE);
        binding.swipeRefreshLayout.setRefreshing(false);
        binding.tvError.setVisibility(View.GONE);

        java.util.List<User> users = (java.util.List<User>) resource.getData();
        if (users != null && !users.isEmpty()) {
            binding.tvEmptyState.setVisibility(View.GONE);
            binding.recyclerViewUsers.setVisibility(View.VISIBLE);
            userAdapter.setUsers(users);
        } else {
            binding.tvEmptyState.setVisibility(View.VISIBLE);
            binding.recyclerViewUsers.setVisibility(View.GONE);
        }
    }

    private void showError(String message) {
        binding.progressBar.setVisibility(View.GONE);
        binding.swipeRefreshLayout.setRefreshing(false);
        binding.tvError.setVisibility(View.VISIBLE);
        binding.tvError.setText(message);
        binding.tvEmptyState.setVisibility(View.GONE);
    }

    private void onUserClicked(User user) {
        Toast.makeText(this, "Selected: " + user.getName(), Toast.LENGTH_SHORT).show();
    }

    @Override
    protected void onDestroy() {
        super.onDestroy();
        binding = null;
    }
}


